 36	typedef struct {
 37	  time_source_type_t type;
 38	  volatile callback_function_t callback;
 39	  volatile callback_data_t callback_data;
 40	  _Atomic bool exit;
 41	  void (*terminate)(void *this);
 42	  pthread_t thread_id;
 43	  pthread_mutex_t mutex;
 44	  pthread_cond_t cond;
