100	static struct timespec next_ms(struct timespec t)
101	{
102	  /* go to next millisecond */
103	  t.tv_nsec += 1000000;
104	  if (t.tv_nsec > 999999999) {
105	    t.tv_nsec -= 1000000000;
106	    t.tv_sec++;
107	  }
108	
109	  return t;
110	}
